#[async_trait]
impl<R: AnalyticsMetricProjectionRepository> AnalyticsMetricEventHandler for AnalyticsMetricProjector<R> {

    async fn on_created(&self, event: AnalyticsMetricCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = AnalyticsMetricProjection::new(
            event.id,
            event.metric_name,
            event.metric_type,
            event.value,
            event.unit,
            event.dimensions,
            event.period_start,
            event.period_end,
            event.aggregation_level,
            event.organization_id,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: AnalyticsMetricUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.metric_name = event.metric_name;
            projection.metric_type = event.metric_type;
            projection.value = event.value;
            projection.unit = event.unit;
            projection.dimensions = event.dimensions;
            projection.period_start = event.period_start;
            projection.period_end = event.period_end;
            projection.aggregation_level = event.aggregation_level;
            projection.organization_id = event.organization_id;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: AnalyticsMetricDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

